MainActivity.kt
class MainActivity : AppCompatActivity() &#123;
    override fun onCreate(savedInstanceState: Bundle?) &#123;
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        showMLoadingDialog(this, &quot;Loading, Hello World!&quot;)
    &#125;

    fun showMLoadingDialog(activity: Activity?, text: String?) &#123;
        var view &#x3D; activity.getLayoutInflater().inflate(R.layout.layout_loading_dialog, null)
        var tv &#x3D; view.findViewById(R.id.tvText) as TextView
        tv.setText(text)

        var dialog &#x3D; MaterialAlertDialogBuilder(this)
        dialog.setView(view)
              .setCancelable(false)
              .create().show();
    &#125;
&#125;



